    // Async command methods

    /// <summary>Send AllocatePushTransport command (0x0000).</summary>
    public Task<InvokeResponse> AllocatePushTransportAsync(
        TransportOptionsStruct transportOptions,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0000, tlv => { WriteTransportOptionsStruct(tlv, 0, transportOptions); }, ct);

    /// <summary>Send DeallocatePushTransport command (0x0002).</summary>
    public Task<InvokeResponse> DeallocatePushTransportAsync(
        ushort connectionID,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0002, tlv => { tlv.AddUInt16(0, connectionID); }, ct);

    /// <summary>Send ModifyPushTransport command (0x0003).</summary>
    public Task<InvokeResponse> ModifyPushTransportAsync(
        ushort connectionID,
        TransportOptionsStruct transportOptions,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0003, tlv =>
        {
            tlv.AddUInt16(0, connectionID);
            WriteTransportOptionsStruct(tlv, 1, transportOptions);
        }, ct);

    /// <summary>Send SetTransportStatus command (0x0004).</summary>
    public Task<InvokeResponse> SetTransportStatusAsync(
        ushort? connectionID,
        TransportStatusEnum transportStatus,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0004, tlv =>
        {
            if (connectionID != null) { tlv.AddUInt16(0, connectionID.Value); } else { tlv.AddNull(0); }
            tlv.AddUInt8(1, (byte)transportStatus);
        }, ct);

    /// <summary>Send ManuallyTriggerTransport command (0x0005).</summary>
    public Task<InvokeResponse> ManuallyTriggerTransportAsync(
        ushort connectionID,
        TriggerActivationReasonEnum activationReason,
        TransportMotionTriggerTimeControlStruct? timeControl = default,
        byte[]? userDefined = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0005, tlv =>
        {
            tlv.AddUInt16(0, connectionID);
            tlv.AddUInt8(1, (byte)activationReason);
            if (timeControl != null) WriteTransportMotionTriggerTimeControlStruct(tlv, 2, timeControl);
            if (userDefined != null) tlv.AddOctetString(3, userDefined);
        }, ct);

    /// <summary>Send FindTransport command (0x0006).</summary>
    public Task<InvokeResponse> FindTransportAsync(
        ushort? connectionID,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0006, tlv => { if (connectionID != null) { tlv.AddUInt16(0, connectionID.Value); } else { tlv.AddNull(0); } }, ct);

