                    break;
                case 2:
                    if (tlv.IsNextNull()) { tlv.GetNull(2); } else { value.CMAFSessionNumber = tlv.GetUnsignedInt(2); }
                    break;
                default:
                    tlv.SkipElement();
                    break;
            }
        }

        tlv.CloseContainer();
        return value;
    }

